mapper.select:
/* checkCompanyDeliveryRouteInfo */
SELECT EXISTS (
	SELECT 1
	FROM company_delivery_route
	WHERE
		delivery_route_id = #{deliveryRouteId}
		AND del_yn = 'N'
)

mapper.update:
	/* updateCompanyAndDeliveryRoute */
    UPDATE company_delivery_route
    SET
    	del_yn = 'N',
        delivery_route_id = #{param.deliveryRouteId},
        delivery_route_cd = #{param.deliveryRouteCd},
        chg_id = #{memberInfo.memberId},
        chg_dt = now()
    WHERE delivery_route_id = #{param.origDeliveryRouteId}
    	AND company_id = #{param.companyId}

	/* deleteCompanyAndDeliveryRoute */
    UPDATE company_delivery_route
    SET
        del_yn = 'Y',
        chg_id = #{memberInfo.memberId},
        chg_dt = now()
    WHERE delivery_route_id = #{param.deliveryRouteId}
    	AND company_id = #{param.companyId}
